INSERT INTO kv_store (key, data, updated_at)
VALUES ('reviews', '[{"id":"r1","name":"Sarah M.","date":"March 2026","rating":5,"text":"Absolutely brilliant! The bikes were in perfect condition, pickup was super easy, and the staff were incredibly helpful. We explored the whole city in one day. Will definitely book again!","source":"Google"},{"id":"r2","name":"Thomas K.","date":"February 2026","rating":5,"text":"Rented the e-bike for a full day and it was the best decision. The range was excellent — we covered 60+ km without any issues. The booking process was straightforward and the bike was ready when we arrived.","source":"Google"},{"id":"r3","name":"Familie Bauer","date":"February 2026","rating":5,"text":"Took the cargo bike with our two kids. Everything was perfectly prepared — helmets for the children, rain cover, clear instructions. The kids loved it. Great local business!","source":"Google"}]'::jsonb, now())
ON CONFLICT (key) DO UPDATE SET data = EXCLUDED.data, updated_at = now();

INSERT INTO kv_store (key, data, updated_at)
VALUES ('faqs', '[{"id":"f1","question":"What''s included with every rental?","answer":"Every rental includes a helmet, a quality lock, and a repair kit. Depending on the bike, you may also get a basket, saddlebag, city map, or child helmets. Check the individual bike page for what''s included."},{"id":"f2","question":"Can I cancel my booking?","answer":"Yes. You can cancel free of charge up to 24 hours before your scheduled pickup. Cancellations made less than 24 hours before are non-refundable. See our full cancellation policy in the FAQ page."},{"id":"f3","question":"Is there a deposit required?","answer":"A deposit may be required at pickup depending on the bike type. For standard city bikes, no deposit is required. For e-bikes and cargo bikes, a refundable deposit of €50–€100 applies."},{"id":"f4","question":"What happens if I return late?","answer":"If you''re running late, please call or message us as soon as possible. Late returns are charged at a prorated hourly rate. We are flexible — just communicate with us in advance."},{"id":"f5","question":"Do I need to bring ID?","answer":"Yes, please bring a valid government-issued ID or passport at pickup. This is required for all rentals."},{"id":"f6","question":"What if the bike breaks down?","answer":"In the unlikely event of a mechanical issue, call our support line. We will do our best to assist you or arrange a replacement. All our bikes are professionally maintained before each rental."}]'::jsonb, now())
ON CONFLICT (key) DO UPDATE SET data = EXCLUDED.data, updated_at = now();

