INSERT INTO kv_store (key, data, updated_at)
VALUES ('tour_pois', '[{"tourId":"lighthouse","lat":53.706783736263546,"lng":7.154148817062379,"title":{"de":"Napoleonschanze","en":"Napoleon’s Redoubt"},"description":{"de":"(Das Schild ist aktuell nicht aufgestellt)\n Die Schanze wurde zur Kontrolle der gegen England verhängten Kontinentalsperre und zur Unterbindung des Schmuggels zwischen Helgoland und den Ostfriesischen Inseln 1811/1812 errichtet","en":"(the sign is currently not installed)\nThe redoubt was built in 1811/1812 to enforce the Continental Blockade imposed against England and to prevent smuggling between Heligoland and the East Frisian Islands"},"category":"history","id":"mo19hc7i7ddx7w7n6t2"},{"tourId":"lighthouse","lat":53.705721800994525,"lng":7.146582305431367,"title":{"de":"Kurtheater Norderney","en":"Kurtheater Norderney"},"description":{"de":"","en":""},"category":"photo","id":"mo19khyz3cg9b0wg2pb"},{"tourId":"lighthouse","lat":53.7093397314587,"lng":7.217524051666261,"title":{"de":"Golf Club Norderney","en":"Golf Club Norderney"},"description":{"de":"Der einzige Dünen-Golfplatz der Ostfriesischen Inseln und zugleich der älteste Links-Course Deutschlands liegt etwa in der Inselmitte zwischen den Campingplatz Spilak und dem Flughafen. Ein Links-Course bezeichnet dabei einen Golfplatz, der sich auf Linksland (aus dem englischen) befindet, d.h. auf welligem, sandigen Untergrund mit keinen oder sehr wenigen Bäumen. Hügel bzw. Dünen, tiefe Topfbunker und natürlich belassenes hohes bzw.","en":"The only dune golf course of the East Frisian Islands—and at the same time the oldest links course in Germany—is located roughly in the middle of the island between the Spilak campsite and the airport.\n\nA links course refers to a golf course situated on “links land” (from English), meaning undulating, sandy terrain with few or no trees. Hills or dunes, deep pot bunkers, and naturally growing tall…"},"category":"photo","id":"mo19vhw6t3x6rgc3qal"},{"tourId":"lighthouse","lat":53.7092042166904,"lng":7.229851484298706,"title":{"de":"Großer Norderneyer Leuchtturm","en":"Great Norderney Lighthouse"},"description":{"de":"Er wurde von 1871 bis 1874 auf einer rund 10 m hohen Düne etwa in der Mitte der ostfriesischen Insel Norderney erbaut.[5] Der Leuchtturm ist mit seinem im oberen Teil achteckigen Querschnitt (mittlere Dicke 6,45 Meter) ein architektonisch erwähnenswertes und mit seiner Höhe von knapp 60 m ü. NN (ohne Laterne 54,6 m) gleichzeitig das höchste Bauwerk der Insel. Unterhalb der Laterne befindet sich eine umlaufende Zuschauergalerie, die man über 252 Stufen erreicht.[4]","en":"It was built between 1871 and 1874 on a dune about 10 meters high, roughly in the middle of the East Frisian island of Norderney.\n\nWith its octagonal cross-section in the upper part (average thickness 6.45 meters), the lighthouse is architecturally noteworthy and, at nearly 60 meters above sea level (54.6 meters without the lantern), it is also the tallest structure on the island.\n\nBelow the lantern there is a surrounding viewing gallery, which can be reached by climbing 252 steps."},"category":"viewpoint","id":"mo19ynrnauugj0d0ri"},{"tourId":"lighthouse","lat":53.70708454237835,"lng":7.229475975036622,"title":{"de":"Flugplatz Norderney","en":"Norderney Airfield"},"description":{"de":"Der Flugplatz Norderney wurde 1970 direkt angrenzend an den Leuchtturm eröffnet. Bereits um 1914 gab es Pläne zur Errichtung eines zivilen Flugplatzes. Der bis dahin bestehende Flugplatz am Westkopf der Insel wurde 1945 von den Alliierten zerstört. Daher wurde 1954 ein Behelfsflugfeld auf einer Wiese am Wattenmeer vor dem Golfhotel in Betrieb genommen, das jedoch wegen immer wiederkehrender Überflutungen geschlossen werden musste und durch den heutigen Flugplatz ersetzt wurde.[1]\n\n1957 wurde der Luftsportverein gegründet, der bis heute den Flugplatz für Fliegerei benutzt.","en":"Norderney Airfield was opened in 1970 directly adjacent to the lighthouse. Plans for the construction of a civilian airfield had already existed around 1914. The previous airfield at the western tip of the island was destroyed by the Allies in 1945.\n\nAs a result, a temporary airstrip was put into operation in 1954 on a meadow by the Wadden Sea in front of the Golf Hotel. However, it had to be closed due to repeated flooding and was replaced by the current airfield.\n\nIn 1957, the aviation club was founded, which still uses the airfield for flying activities today."},"category":"photo","id":"mo1a0yd55pgjwasq7q8"},{"tourId":"weststrand","lat":53.72024880802122,"lng":7.238531112670899,"title":{"de":"Oase Strand","en":"Oasis Beach"},"description":{"de":"Der FKK Strand an der Oase hat sich in den letzten Jahren durch seine umfangreiche Infrastruktur zu einem der beliebtesten Strände auf Norderney entwickelt. Das alljährlich aufgebaute, mit Holz verkleidete „Containerdorf“ beherbergt ein kleines Café mit einer vollständigen Strandgastronomie. Außer Pommes, Currywurst, Backfisch und Frikadellen gibt es dort Cappuccino, Late Macchiato und natürlich Bier und alkoholfreie Getränke. Die Terrasse bietet einen Blick auf unberührten Strand und Wasser, wie es ihn sonst nur selten gibt.","en":"The nudist beach at the Oase has, in recent years, developed into one of the most popular beaches on Norderney thanks to its extensive infrastructure.\n\nThe annually constructed “container village,” clad in wood, houses a small café with full beach catering. In addition to fries, currywurst, fried fish, and meatballs, you can also get cappuccino, latte macchiato, and of course beer and soft drinks.\n\nThe terrace offers a view of unspoiled beach and sea—something that is otherwise rarely found in this form."},"category":"nature","id":"mo1chwqck100hjjttb"},{"tourId":"weststrand","lat":53.7214431084662,"lng":7.236857414245606,"title":{"de":"Oase Strand","en":"Oasis Beach"},"description":{"de":"","en":""},"category":"photo","id":"mo1ciu8d63w2kcygehf"},{"tourId":"weststrand","lat":53.71294992833348,"lng":7.2587013244628915,"title":{"de":"letzter parkplatz norderney","en":"Last parking area on Norderney"},"description":{"de":"Von hier ist alles Naturschutzgebiet bis zum Wrack.“**\n","en":"From here on, everything is a nature reserve up to the wreck"},"category":"parking","id":"mo1cla170zsunpjs0if"}]'::jsonb, now())
